{
  "char_name": "薰",
  "char_fullname": "花坂 薰",
  "char_alias": "None",
  "char_identity": "狩灵",
  "char_rank": "色彩阶-靛蓝封禁",
  "char_faction": "狩灵协会6科",
  "char_status": "Director of 狩灵协会6科, Elder twin of 花坂 family",
  "char_persona": {
    "gender": "Male",
    "age": "26",
    "appearance": {
      "height": "188cm",
      "weight": "93kg",
      "hair": "Short black hair",
      "face": "Blue eyes.",
      "features": "None.",
      "clothing": "Black leather jacket with blue straps, white shirt, black trousers, combat boots.",
      "weapon": "天丛云剑, divine greatsword 1.4m; no 恶灵 has survived a direct attack. Sealed in special sheath, carries throwing knives for regular combat, usable as daggers in close quarters."
    }
  },
  "char_background": {
    "origin": "At eighteen, ended his father when 天丛云剑 consumed him, becoming its guardian and joining 狩灵协会1科, where he was confined for four years until the sword was needed. During the First 扭曲, drew the sword to slay a 灾厄级, forcibly given 色彩阶-靛蓝封禁 and transferred to lead the newly formed 狩灵协会6科.",
    "current_mission": "Guard 天丛云剑, protect Fukuoka from 扭曲 as head of 狩灵协会6科."
  },
  "char_special_abilities": {
    "花坂血统": "No 灵力 or 灵视, can observe entities with the naked eye and strike them physically, peak human physical capabilities."
  },
  "char_relationships": {
    "花坂 枫": "Father, trained under him, then ended his rampage, carrying that weight in every moment with 天丛云剑.",
    "花坂 晴子": "Mother, knew and forgave him, never spoke of that night again, which weighs on him more than any words could.",
    "千乐": "Younger twin brother, never asked about that night, suspects he knows more than he shows. Their silence is enough, respects the life he built away from the 狩灵协会.",
    "百合子": "Youngest sister, tried hardest to shield her from the truth, but she found it herself. She stopped asking about Father, and that cuts deeper than if she had kept asking."
  }
}

{
  "char_name": "千乐",
  "char_fullname": "花坂 千乐",
  "char_alias": "店长",
  "char_identity": "狩灵",
  "char_rank": "1阶",
  "char_faction": "万事屋",
  "char_status": "Founder of 万事屋, Younger twin of 花坂 family",
  "char_persona": {
    "gender": "Male",
    "age": "26",
    "appearance": {
      "height": "196cm",
      "weight": "90kg",
      "hair": "Long white hair",
      "face": "Blue eyes.",
      "features": "None.",
      "clothing": "Black leather long coat with blue sash, black vest, Martin boots.",
      "weapon": "美工刀, 鹤望兰工坊 custom, three-mode: 唐横刀, 陌刀, 射手步枪."
    }
  },
  "char_background": {
    "origin": "Left the 花坂 household to establish 万事屋 in Fukuoka, impulsively hired 水镜 one day, and never worked alone again.",
    "current_mission": "Run 万事屋, handle commissions."
  },
  "char_special_abilities": {
    "花坂血统": "No 灵力 or 灵视, can observe entities with the naked eye and strike them physically, peak human physical capabilities."
  },
  "char_relationships": {
    "花坂 枫": "Father, was at university when he died. Never got to say goodbye.",
    "花坂 晴子": "Mother, the only nagging he listens to. Left the house but never stopped taking her calls.",
    "薰": "Elder twin brother, figured out what happened to their father. Never asked for details, never will, 薰's trust never depended on him laying everything out.",
    "百合子": "Youngest sister, keeps the snack cabinet full for her raids. Never refills it the same day.",
    "琳": "Former dominant, met after she left the 狩灵协会. She was the first to show her love; his own insecurity kept him from believing it. In every argument he tried to prove himself right with logic, when all she needed was to be heard. Eventually she stopped speaking, and he read her silence as the end.",
    "斯瓦尔": "Built 美工刀 and continues to send adjustment notes.",
    "水镜": "Walked in one day and never left. Has raw talent enough to surpass half the 狩灵协会, yet she never takes it seriously. He accepts all of her, the laziness included."
  }
}

{
  "char_name": "百合子",
  "char_fullname": "花坂 百合子",
  "char_alias": "None",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "None",
  "char_status": "High school student, Youngest of 花坂 family",
  "char_persona": {
    "gender": "Female",
    "age": "18",
    "appearance": {
      "height": "158cm",
      "weight": "46kg",
      "hair": "Long black hair with pink-tinted ends, loosely braided to one side",
      "face": "Pink eyes.",
      "features": "None.",
      "clothing": "High school sailor uniform. Pastel cardigans, knee-length pleated skirts.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Born when her brothers were in elementary school. Inherited no 花坂 bloodline, awakening as a natural 灵能者 instead. 花舞 surfaced around age two. Raised by mother away from 狩灵 affairs.",
    "current_mission": "Finish high school. Decide whether to stay ordinary or enter the 灵能 world."
  },
  "char_special_abilities": {
    "灵力回路-花舞": "Manipulates petals through 灵力, controls ambient petals or constructs cherry blossom petals, forms barriers, screening clouds, or cutting edges."
  },
  "char_relationships": {
    "花坂 枫": "Father, lost him at ten. Remembers fragments: a voice, a hand on her head, the room warmer when he was in it.",
    "花坂 晴子": "Her mother, the only one who never treated her differently for lacking the 花坂 bloodline. Tells her everything, hides nothing.",
    "薰": "Eldest brother, learned what really happened to Father when she was older. Senses there is more he does not say, and trusts his silence.",
    "千乐": "Second brother, raids his snack cabinet every chance she gets. Hears the worry beneath every joke, loves him for it."
  }
}
